INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00643', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟費用之擔保，下列敘述何者錯誤？', '["被告已為本案之言詞辯論者，不得聲請命原告供擔保。但應供擔保之事由知悉在後者，不在此限", "聲請命供擔保之裁定，不得抗告", "法院命原告供擔保者，定擔保額，以被告於各審應支出之費用總額為準", "原告於裁定所定供擔保之期間內不供擔保者，法院應以裁定駁回其訴。但在裁定前已供擔保者，不在 此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00644', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，為關於訴訟標的之闡明？', '["審判長向被告闡明，詢問其是否提出同時履行抗辯", "審判長向原告闡明應提出證據", "闡明原告表明請求所依據之理由", "被告為抵銷抗辯，審判長不確定被告是否有提起反訴之意思，闡明使被告表明"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00645', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於對無訴訟能力人、訴訟代理人之送達，下列敘述何者正確？', '["訴訟代理人應受特別委任，方能對其送達", "對於無訴訟能力人為送達者，應向其全體法定代理人為之", "當事人委任2位以上之訴訟代理人者，應向當事人與全體訴訟代理人為送達", "對於未滿16歲且無訴訟能力之人為送達者，應囑託其學校或安置機關之負責人為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00646', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於期日與期間，下列敘述何者正確？', '["民事訴訟法關於期間之計算，依民法之規定", "當事人工作地點不在受訴法院所在地者，受訴法院應囑託其工作地之法院送達之", "當事人不在法院所在地居住者，而其訴訟代理人住居法院所在地，關於在途期間之扣除，應以當事 人所在地計算之", "不變期間，如有重大理由，得伸長或縮短之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00647', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟程序停止，下列敘述何者正確？', '["當事人死亡者，訴訟主體消滅，訴訟繫屬消滅，無訴訟停止與續行之問題", "委任訴訟代理人之案件，當事人喪失訴訟能力時，無法與訴訟代理人商討案情，訴訟程序當然停止", "當事人得以合意停止訴訟程序，不變期間亦隨之停止進行", "合意停止訴訟程序之當事人，自陳明合意停止時起，如於4個月內不續行訴訟者，視為撤回其訴或 上訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00648', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '原告與被告在法院成立和解，下列敘述何者錯誤？', '["該和解與確定判決有同一之效力", "如該和解有無效之原因，原告得請求繼續審判", "如該和解有得撤銷之原因，被告得提起撤銷和解之訴", "法院無庸就此訴訟為判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00649', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲與乙間之民事訴訟，經兩造言詞辯論後，甲以書狀撤回其起訴，乙就該撤回未表示任何意見。自何 時起，視為乙同意甲撤回其起訴？', '["甲向法院提出撤回書狀", "甲之撤回書狀送達乙", "審判長宣示言詞辯論終結", "甲之撤回書狀送達乙後經10日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00650', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '原告甲列乙為被告，下列何者，應由乙負舉證責任？', '["甲主張其為乙獨居之父提供三餐，爰依不當得利法律關係請求返還相關餐費。關於無法律上原因之 事實", "甲請求確認乙對現為甲占有且未經建物第一次所有權登記A屋之所有權不存在。關於A屋確為乙 所有之事實", "甲主張因受乙不堪同居之虐待而請求裁判離婚。關於有無不堪同居虐待之事實", "甲請求確認與乙親子關係存在。關於其親子關係成立之事實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00651', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何種情形，法院應以裁定駁回一造言詞辯論之聲請，並延展辯論期日？', '["不到場之當事人已於相當時期受合法通知", "到場之當事人所提出之聲明、事實或證據，已於相當時期通知他造", "到場當事人於法院應依職權調查之事項已為必要之證明", "當事人之不到場可認為係因天災"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00652', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟中移付調解，下列敘述何者正確？', '["調解程序中，調解委員所為之勸導，使當事人成立相互讓步之方案，應成為本案訴訟之爭點簡化協議", "調解程序中，法官所為之勸導及當事人所為之陳述或讓步，於調解不成立後之本案訴訟，不得採為 裁判之基礎", "第二審訴訟繫屬中，法院於必要時，應依職權將事件移付調解", "訴訟繫屬中由法官依職權移付調解者，以2次為限。但經當事人合意者，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
